+using Microsoft.ML;
+using TicketClassifier.Models;
+
+namespace TicketClassifier.Services;
+
+public static class TicketModelTrainer
+{
+    public static string TrainAndSave(string dataPath, string modelPath)
+    {
+        var mlContext = new MLContext(seed: 42);
+
+        var data = mlContext.Data.LoadFromTextFile<TicketInput>(
+            dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);
+
+        var split = mlContext.Data.TrainTestSplit(data, testFraction: 0.2, seed: 42);
+
+        var pipeline = mlContext.Transforms.Text.FeaturizeText("SubjectFeatures", nameof(TicketInput.Subject))
+            .Append(mlContext.Transforms.Text.FeaturizeText("DescriptionFeatures", nameof(TicketInput.Description)))
+            .Append(mlContext.Transforms.Concatenate("Features", "SubjectFeatures", "DescriptionFeatures", nameof(TicketInput.Priority)))
+            .Append(mlContext.Transforms.Conversion.MapValueToKey("Label", nameof(TicketInput.Category)))
+            .Append(mlContext.MulticlassClassification.Trainers.SdcaMaximumEntropy("Label", "Features"))
+            .Append(mlContext.Transforms.Conversion.MapKeyToValue("PredictedLabel"));
+
+        var model = pipeline.Fit(split.TrainSet);
+
+        var predictions = model.Transform(split.TestSet);
+        var metrics = mlContext.MulticlassClassification.Evaluate(predictions);
+
+        var report = $"""
+            === Model Evaluation Metrics ===
+            MacroAccuracy:    {metrics.MacroAccuracy:F4}
+            MicroAccuracy:    {metrics.MicroAccuracy:F4}
+            LogLoss:          {metrics.LogLoss:F4}
+            LogLossReduction: {metrics.LogLossReduction:F4}
+            """;
+
+        mlContext.Model.Save(model, data.Schema, modelPath);
+        return report;
+    }
+}
